/* ── Cart & Orders (runtime) ──────────────────────────────────── */
let cart = [];          // [{ id, productId, quantity }]
let orders = [];        // [{ id, items, total, customer, paymentMethod, status, createdAt }]
let nextCartId = 1;
let nextOrderId = 1000;

/* ── Helper: deep-clone to prevent mutation ──────────────────── */
const clone = obj => JSON.parse(JSON.stringify(obj));

module.exports = {
  products,
  categories,
  sellers,
  cart,
  orders,
  clone,
  addProduct(p) {
    const id = products.length ? Math.max(...products.map(x => x.id)) + 1 : 1;
    const product = { id, ...p, rating: p.rating || 4.0, reviewCount: p.reviewCount || 0, createdAt: new Date().toISOString().split('T')[0] };
    products.push(product);
    // update category count
    const cat = categories.find(c => c.slug === product.category);
    if (cat) cat.count += 1;
    return product;
  },
  addToCart(productId, quantity = 1) {
    const existing = cart.find(c => c.productId === productId);
    if (existing) {
      existing.quantity += quantity;
      return existing;
    }
    const item = { id: nextCartId++, productId, quantity };
    cart.push(item);
    return item;
  },
  updateCartItem(id, quantity) {
    const item = cart.find(c => c.id === id);
    if (!item) return null;
    item.quantity = quantity;
    return item;
  },
  removeCartItem(id) {
    const idx = cart.findIndex(c => c.id === id);
    if (idx === -1) return false;
    cart.splice(idx, 1);
    return true;
  },
  clearCart() {
    cart.length = 0;
  },
  createOrder(customer, paymentMethod) {
    const items = cart.map(c => {
      const prod = products.find(p => p.id === c.productId);
      return { ...c, product: prod ? clone(prod) : null };
    });
    const total = items.reduce((sum, i) => sum + (i.product ? i.product.price * i.quantity : 0), 0);
    const order = { id: nextOrderId++, items, total, customer: clone(customer), paymentMethod, status: 'confirmed', createdAt: new Date().toISOString() };
    orders.push(order);
    cart.length = 0;
    return order;
  },
};
